/**
 * Cobordism logits-concatenation parity test.
 *
 * Pipeline.ts lm_head fanout (pipeline.ts ~286-313 and ~728-772) does:
 *
 *   const partials = await Promise.all(
 *     this.cobordismStations.map((cs) => cs.station.cobordismLmHead({...}))
 *   );
 *   const totalVocab = max(cs.vocabEnd over shards);
 *   const logits = new Float32Array(totalVocab);
 *   for (let i = 0; i < this.cobordismStations.length; i++) {
 *     const cs = this.cobordismStations[i]!;
 *     const partial = partials[i]!;
 *     if (partial.length !== cs.vocabEnd - cs.vocabStart) throw ...;
 *     logits.set(partial, cs.vocabStart);
 *   }
 *
 * Hypothesis under test: because `cs.vocabStart` is used as the WRITE OFFSET
 * (not `i * shardWidth`), the reconstruction MUST be insensitive to the
 * iteration order of `cobordismStations`. We verify this empirically against a
 * vocab-order reference, plus probe gap-tolerance and overlap-detection.
 *
 * No live mesh, no fat-station, no kernel — just the pure reconstruction
 * logic on synthetic partials. This file owns its own copy of the loop so a
 * future drift in pipeline.ts surfaces as a parity diff.
 */

import { describe, expect, it } from 'vitest';

interface CobordismShard {
  vocabStart: number;
  vocabEnd: number;
  /** synthetic logits for this shard's vocab range */
  partial: Float32Array;
}

/**
 * Mirrors pipeline.ts cobordism lm_head reconstruction.
 *
 * `shards[i]` is paired with `partials[i]` (the result of
 * `Promise.all(shards.map(s => s.station.cobordismLmHead(...)))`).
 *
 * NOTE: this function does NOT detect overlapping vocab ranges; later writes
 * silently overwrite earlier ones. That property is what the overlap test
 * documents.
 */
function reconstruct(shards: CobordismShard[]): Float32Array {
  const totalVocab = shards.reduce(
    (acc, cs) => Math.max(acc, cs.vocabEnd),
    0,
  );
  const logits = new Float32Array(totalVocab);
  for (let i = 0; i < shards.length; i++) {
    const cs = shards[i]!;
    const partial = cs.partial;
    if (partial.length !== cs.vocabEnd - cs.vocabStart) {
      throw new Error(
        `cobordism lm_head: shard ${i} returned ${partial.length} floats, ` +
          `expected ${cs.vocabEnd - cs.vocabStart} for vocab [${cs.vocabStart}, ${cs.vocabEnd})`,
      );
    }
    logits.set(partial, cs.vocabStart);
  }
  return logits;
}

/**
 * Realistic-ish qwen-coder-7b shape: 152K vocab split 8 ways at 19K each.
 * Each shard's partial logits are deterministic, vocab-position dependent so
 * we can detect any misordering in the assembled vector.
 */
const VOCAB_SIZE = 152_064;
const SHARD_COUNT = 8;
const SHARD_WIDTH = VOCAB_SIZE / SHARD_COUNT; // 19_008

function buildShards(opts?: {
  /** truncate the LAST shard's vocabEnd to simulate a documented coverage gap */
  truncateLastBy?: number;
  /** make adjacent shards overlap by N tokens */
  overlapBy?: number;
}): CobordismShard[] {
  const shards: CobordismShard[] = [];
  for (let i = 0; i < SHARD_COUNT; i++) {
    const vocabStart = i * SHARD_WIDTH;
    let vocabEnd = vocabStart + SHARD_WIDTH;

    if (opts?.overlapBy && i > 0) {
      // grow the start backwards into the previous shard
      const overlapStart = vocabStart - opts.overlapBy;
      const len = vocabEnd - overlapStart;
      const partial = new Float32Array(len);
      for (let j = 0; j < len; j++) {
        partial[j] = (overlapStart + j) + 0.5; // distinct from non-overlap
      }
      shards.push({ vocabStart: overlapStart, vocabEnd, partial });
      continue;
    }

    if (opts?.truncateLastBy && i === SHARD_COUNT - 1) {
      vocabEnd -= opts.truncateLastBy;
    }
    const len = vocabEnd - vocabStart;
    const partial = new Float32Array(len);
    for (let j = 0; j < len; j++) {
      // Encode the absolute vocab index so any misordering is detectable.
      partial[j] = vocabStart + j;
    }
    shards.push({ vocabStart, vocabEnd, partial });
  }
  return shards;
}

function shuffle<T>(arr: T[], seed = 0xc0bd): T[] {
  // deterministic LCG shuffle
  const out = arr.slice();
  let s = seed >>> 0;
  for (let i = out.length - 1; i > 0; i--) {
    s = (s * 1664525 + 1013904223) >>> 0;
    const j = s % (i + 1);
    [out[i], out[j]] = [out[j]!, out[i]!];
  }
  return out;
}

describe('cobordism logits concatenation: order-sensitivity', () => {
  it('vocab-order shards reconstruct the identity vector (reference)', () => {
    const shards = buildShards();
    const logits = reconstruct(shards);
    expect(logits.length).toBe(VOCAB_SIZE);
    // Each slot should equal its vocab index by construction.
    for (let i = 0; i < VOCAB_SIZE; i += 4096) {
      expect(logits[i]).toBe(i);
    }
    expect(logits[VOCAB_SIZE - 1]).toBe(VOCAB_SIZE - 1);
  });

  it('REVERSED construction order matches vocab-order reference', () => {
    const reference = reconstruct(buildShards());
    const reversed = reconstruct(buildShards().reverse());
    expect(reversed.length).toBe(reference.length);
    expect(reversed).toEqual(reference);
  });

  it('SHUFFLED construction order matches vocab-order reference (10 seeds)', () => {
    const reference = reconstruct(buildShards());
    for (let seed = 1; seed <= 10; seed++) {
      const shuffled = reconstruct(shuffle(buildShards(), seed));
      expect(
        shuffled,
        `shuffled seed=${seed} must equal vocab-order reference`,
      ).toEqual(reference);
    }
  });
});

describe('cobordism logits concatenation: gap tolerance', () => {
  it('truncated last shard leaves the gap at zero (no throw)', () => {
    // Shard 7 covers [133_056, 151_936) instead of [..., 152_064).
    // Documented anomaly per project_inference_cluster_shape memory.
    const gap = 128;
    const shards = buildShards({ truncateLastBy: gap });
    const logits = reconstruct(shards);
    // Total length is determined by max(vocabEnd) — so logits.length is the
    // truncated end, not the nominal VOCAB_SIZE.
    expect(logits.length).toBe(VOCAB_SIZE - gap);
    // Last covered slot is non-zero.
    const lastCovered = VOCAB_SIZE - gap - 1;
    expect(logits[lastCovered]).toBe(lastCovered);
  });

  it('explicit gap inside the vocab leaves zeros there but downstream argmax still finds a non-zero peak', () => {
    // Drop shard 3 (vocab [57_024, 76_032)) entirely. Place a peak somewhere
    // inside shard 5 — argmax should still return the peak index.
    const all = buildShards();
    const sparse = all.filter((_, i) => i !== 3);
    const peakShardIdx = 5;
    const peakOffset = 1234;
    const peakAbs = peakShardIdx * SHARD_WIDTH + peakOffset;
    sparse.forEach((s) => {
      if (s.vocabStart === peakShardIdx * SHARD_WIDTH) {
        s.partial[peakOffset] = 1e9;
      }
    });
    const logits = reconstruct(sparse);
    // Gap region is initial zero.
    for (let i = 57_024; i < 76_032; i += 1024) {
      expect(logits[i]).toBe(0);
    }
    // argmax: simple O(n) scan
    let bestIdx = 0;
    let bestVal = -Infinity;
    for (let i = 0; i < logits.length; i++) {
      if (logits[i]! > bestVal) {
        bestVal = logits[i]!;
        bestIdx = i;
      }
    }
    expect(bestIdx).toBe(peakAbs);
    expect(bestVal).toBe(1e9);
  });
});

describe('cobordism logits concatenation: overlap behavior', () => {
  it('overlapping shards SILENTLY overwrite — no throw, last writer wins', () => {
    // Build shards where each non-zero shard starts 16 tokens INTO the
    // previous shard's range. The reconstruction has no overlap detector.
    const shards = buildShards({ overlapBy: 16 });
    expect(() => reconstruct(shards)).not.toThrow();
    const logits = reconstruct(shards);
    // In the overlap region between shard 0 ([0, 19008)) and shard 1
    // ([18992, 38016)), positions 18992..19007 should hold shard 1's values
    // (the second writer), not shard 0's. Shard 1's overlap entries are
    // `(overlapStart + j) + 0.5`, so position 18992 should be 18992.5.
    expect(logits[18992]).toBe(18992.5);
    expect(logits[19007]).toBe(19007.5);
    // Just outside the overlap, shard 0 owns the value (integer).
    expect(logits[18991]).toBe(18991);
  });

  it('shard with WRONG length throws immediately (the only invariant guarded)', () => {
    const shards = buildShards();
    // Corrupt shard 4: claim vocab range of 19008, but ship 19000 floats.
    shards[4]!.partial = new Float32Array(SHARD_WIDTH - 8);
    expect(() => reconstruct(shards)).toThrow(/returned 19000 floats/);
  });
});
